        fint.resolve(0);
        assertEquals("available",fstr.get());
        assertNotEquals(1,fint.get());
    }
    @Test
    public void getTTimeTest(){// resolve & getT Test
        TimeUnit unit =TimeUnit.MICROSECONDS;
        assertNull(flong.get(100,unit));
    }
}

